previewCss:
.darma-loader-darma-research-constellation-trace-spinner { --speed: var(--loader-speed, 1s); --accent: var(--loader-color, #60a5fa); --accent-2: var(--loader-secondary-color, #c084fc); width: var(--loader-size, 88px); height: var(--loader-size, 88px); position: relative; border-radius: 50%; animation: darma-loader-darma-research-constellation-trace-spinner-constellation-rotate calc(var(--speed) * 4) linear infinite; }
.darma-loader-darma-research-constellation-trace-spinner::before { content: ""; position: absolute; inset: 10%; border-radius: 50%; border: 1px dashed color-mix(in srgb, var(--accent-2) 55%, transparent); }
.darma-loader-darma-research-constellation-trace-spinner::after { content: ""; position: absolute; inset: 20%; border-radius: 50%; background: conic-gradient(from 20deg, transparent 0 60%, var(--accent) 75%, transparent 90%); mask: radial-gradient(farthest-side, transparent 62%, #000 64% 72%, transparent 74%); }
.darma-loader-darma-research-constellation-trace-spinner span { position: absolute; width: 10%; aspect-ratio: 1; border-radius: 50%; background: #fff; box-shadow: 0 0 12px 3px var(--accent); }
.darma-loader-darma-research-constellation-trace-spinner span:nth-child(1){ left:45%; top:0; } .darma-loader-darma-research-constellation-trace-spinner span:nth-child(2){ right:5%; top:28%; background:var(--accent-2); } .darma-loader-darma-research-constellation-trace-spinner span:nth-child(3){ right:18%; bottom:8%; } .darma-loader-darma-research-constellation-trace-spinner span:nth-child(4){ left:14%; bottom:14%; background:var(--accent-2); } .darma-loader-darma-research-constellation-trace-spinner span:nth-child(5){ left:0; top:36%; }
@keyframes darma-loader-darma-research-constellation-trace-spinner-constellation-rotate { to { rotate: 360deg; } }

